<template>
    <input type="text" id="add-item" placeholder="请输入待办事项：" v-model="title" @keyup.enter="CreateItem">
</template>

<script>
export default {
    name: 'AddItem',
    props: ['PushItem'],
    data() {
        return {
            title: ''
        }
    },
    methods: {
        CreateItem() {
            if (!this.title.trim()) return
            const item = {
                id: Date.now(),
                title: this.title,
                done: false
            }
            this.PushItem(item)
            this.title = ''
        }
    }
}
</script>

<style>
#add-item {
    display: block;
    width: 50%;
    height: 5vh;
    margin: 0 auto;
    padding: 20px;
    box-sizing: border-box;
}
</style>