<template>
    <li id="item-card">
        <input type="radio" :checked="item.done" @click="IsDone(item.id)">
        <p>{{ item.title }}</p>
        <button @click="DelItem(item.id)">删除</button>
    </li>
</template>

<script>
export default {
    name: 'ItemCard',
    props: ['item', 'CheckIsDone', 'EraseItem'],
    methods: {
        IsDone(id) {
            this.CheckIsDone(id)
        },
        DelItem(id) {
            if (confirm('确定删除吗？')) {
                this.EraseItem(id)
            }
        }
    }
}
</script>

<style>
#item-card {
    list-style: none;
    position: relative;
    width: 100%;
    height: 5vh;
    line-height: 5vh;
    margin: 0 auto;
    border-bottom: 1px solid black;
    background-color: bisque;
}

#item-card input {
    float: left;
    vertical-align: middle;
    height: 100%;
    margin-left: 3%;
}

#item-card p {
    float: left;
    margin-left: 3%;
}

#item-card button {
    position: absolute;
    top: 50%;
    right: 2%;
    transform: translate(-50%, -50%);
    border: 1px solid black;
    width: 10%;
    height: 60%;
    background-color: red;
    color: white;
    display: none;
}

#item-card:hover button {
    display: block;
}
</style>