<template>
    <div id="select-all" v-show="itemCount">
        <input type="radio" @click="AllIn" :checked="isAllIn">
        <p>已完成{{ doneCount }} / 全部{{ itemCount }}</p>
        <button @click="DelSelect">清除已完成任务</button>
    </div>
</template>

<script>
export default {
    name: 'SelectAll',
    props: ['items', 'DoneAll', 'EraseItem'],
    computed: {
        itemCount() {
            return this.items.length
        },
        doneCount() {
            // return this.items.filter(item => item.done).length
            return this.items.reduce((pre, item) => pre + (item.done ? 1 : 0), 0)
        },
        isAllIn() {
            return this.doneCount === this.itemCount && this.itemCount > 0
        }
    },
    methods: {
        AllIn() {
            this.DoneAll()
        },
        DelSelect() {
            if (confirm('确定删除已选吗？')) {
                this.items.forEach((item) => {
                    if (item.done) {
                        this.EraseItem(item.id)
                    }
                })
            }
        }
    }
}
</script>

<style>
#select-all {
    position: relative;
    width: 50%;
    height: 5vh;
    line-height: 5vh;
    margin: 0 auto;
    border-bottom: 1px solid black;
    background-color: silver;
}

#select-all input {
    float: left;
    vertical-align: middle;
    height: 100%;
    margin-left: 3%;
}

#select-all p {
    float: left;
    margin-left: 8%;
}

#select-all button {
    position: absolute;
    top: 50%;
    right: -10%;
    transform: translate(-50%, -50%);
    border: 1px solid black;
    padding: 10px;
    padding-left: 0;
    padding-right: 0;
    width: 25%;
    background-color: red;
    color: white;
}
</style>