<template>
  <div id="app">
    <AddItem :PushItem="PushItem"></AddItem>
    <ItemList :items="items" :CheckIsDone="CheckIsDone" :EraseItem="EraseItem"></ItemList>
    <SelectAll :items="items" :DoneAll="DoneAll" :EraseItem="EraseItem"></SelectAll>
  </div>
</template>

<script>
import AddItem from './components/AddItem.vue';
import ItemList from './components/ItemList.vue';
import SelectAll from './components/SelectAll.vue';

export default {
  name: 'App',
  components: {
    AddItem,
    ItemList,
    SelectAll
  },
  mounted() {
    this.LoadItems()
  },
  data() {
    return {
      items: []
    }
  },
  methods: {
    PushItem(item) {
      this.items.unshift(item)
    },
    CheckIsDone(id) {
      this.items.forEach((item) => {
        if (item.id === id) {
          item.done = !item.done
        }
      })
    },
    EraseItem(id) {
      this.items = this.items.filter(item => item.id !== id)
    },
    DoneAll() {
      let isAllIn = this.items.reduce((pre, item) => pre + (item.done ? 1 : 0), 0) === this.items.length
      // this.items.forEach((item) => {
      //   if (item.done === false) {
      //     isAllIn = false;
      //   }
      // })
      if (isAllIn) {
        this.items.forEach((item) => {
          item.done = false
        })
      }
      else {
        this.items.forEach((item) => {
          item.done = true
        })
      }
    },
    SaveItems() {
      localStorage.setItem('items', JSON.stringify(this.items))
    },
    LoadItems() {
      const JSONStr = localStorage.getItem('items')
      this.items = JSON.parse(JSONStr) || []
    }
  },
  watch: {
    items: {
      handler() {
        this.SaveItems();
      },
      deep: true
    }
  }
}
</script>

<style>
* {
  margin: 0;
  padding: 0;
}

#app {
  width: 50vw;
  height: 80vh;
  margin-top: 10vh;
  margin-left: auto;
  margin-right: auto;
}
</style>
